import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import Layout from '../components/layout/Layout';
import Pagination from '../components/common/Pagination';
import api from '../services/api';
import { formatCurrency, formatDate } from '../utils/helpers';

const LIMIT = 20;

export default function Invoices() {
  const [invoices, setInvoices] = useState([]);
  const [total,    setTotal]    = useState(0);
  const [loading,  setLoading]  = useState(true);
  const [search,   setSearch]   = useState('');
  const [status,   setStatus]   = useState('');      // draft | final | ''
  const [payStatus,setPayStatus]= useState('');
  const [billing,  setBilling]  = useState('');      // gst | non-gst | ''
  const [from,     setFrom]     = useState('');
  const [to,       setTo]       = useState('');
  const [page,     setPage]     = useState(1);

  const fetch = useCallback(async () => {
    setLoading(true);
    try {
      const p = new URLSearchParams({ page, limit: LIMIT });
      if (search)    p.append('search',      search);
      if (status)    p.append('status',      status);
      if (payStatus) p.append('payStatus',   payStatus);
      if (billing)   p.append('billingType', billing);
      if (from)      p.append('from',        from);
      if (to)        p.append('to',          to);
      const res = await api.get(`/invoices?${p}`);
      setInvoices(res.data.data);
      setTotal(res.data.total);
    } finally { setLoading(false); }
  }, [search, status, payStatus, billing, from, to, page]);

  useEffect(() => { fetch(); }, [fetch]);

  const pages = Math.ceil(total / LIMIT);

  const FilterBtn = ({ label, val, current, onChange }) => (
    <button
      className={`btn btn-sm ${current === val ? 'btn-primary' : 'btn-secondary'}`}
      onClick={() => { onChange(val === current ? '' : val); setPage(1); }}
    >
      {label}
    </button>
  );

  return (
    <Layout title="Invoices">
      {/* Search */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 18 }}>
        <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'center' }}>
          <div style={{ position: 'relative', flex: 1, maxWidth: 300 }}>
            <span style={{ position: 'absolute', left: 11, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)', pointerEvents: 'none' }}>&#128269;</span>
            <input className="form-control" style={{ paddingLeft: 34 }} placeholder="Invoice no, customer, mobile..." value={search} onChange={(e) => { setSearch(e.target.value); setPage(1); }} />
          </div>
          <input type="date" className="form-control" style={{ width: 150 }} value={from} onChange={(e) => { setFrom(e.target.value); setPage(1); }} />
          <input type="date" className="form-control" style={{ width: 150 }} value={to}   onChange={(e) => { setTo(e.target.value);   setPage(1); }} />
          <Link to="/billing/new" className="btn btn-primary" style={{ marginLeft: 'auto' }}>+ New Invoice</Link>
        </div>
        {/* Filter chips */}
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
          <span style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600 }}>Status:</span>
          <FilterBtn label="Draft"       val="draft"   current={status}    onChange={setStatus} />
          <FilterBtn label="Final"       val="final"   current={status}    onChange={setStatus} />
          <span style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600, marginLeft: 8 }}>Payment:</span>
          <FilterBtn label="Paid"        val="paid"    current={payStatus} onChange={setPayStatus} />
          <FilterBtn label="Partial"     val="partial" current={payStatus} onChange={setPayStatus} />
          <FilterBtn label="Pending"     val="pending" current={payStatus} onChange={setPayStatus} />
          <FilterBtn label="Credit"      val="credit"  current={payStatus} onChange={setPayStatus} />
          <span style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600, marginLeft: 8 }}>Type:</span>
          <FilterBtn label="GST"         val="gst"     current={billing}   onChange={setBilling} />
          <FilterBtn label="Non-GST"     val="non-gst" current={billing}   onChange={setBilling} />
        </div>
      </div>

      <div className="card">
        <div className="card-header">
          <span className="card-title">Invoices ({total})</span>
        </div>
        <div className="table-container">
          {loading ? <div className="loading"><div className="spinner" /></div> : (
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Invoice No</th>
                  <th>Date</th>
                  <th>Customer</th>
                  <th>Type</th>
                  <th>Doc Status</th>
                  <th className="text-right">Total</th>
                  <th className="text-right">Paid</th>
                  <th className="text-right">Due</th>
                  <th>Payment</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {invoices.length === 0 && <tr><td colSpan={11} className="text-center" style={{ padding: 40, color: 'var(--text-muted)' }}>No invoices found</td></tr>}
                {invoices.map((inv, i) => (
                  <tr key={inv._id}>
                    <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{(page - 1) * LIMIT + i + 1}</td>
                    <td><Link to={`/billing/${inv._id}`} style={{ color: 'var(--primary)', fontWeight: 700 }}>{inv.invoiceNumber}</Link></td>
                    <td style={{ fontSize: 12 }}>{formatDate(inv.invoiceDate)}</td>
                    <td style={{ fontWeight: 500 }}>{inv.customerName}</td>
                    <td><span className={`badge badge-${inv.billingType === 'gst' ? 'info' : 'default'}`}>{inv.billingType?.toUpperCase()}</span></td>
                    <td>
                      <span className={`badge badge-${inv.status === 'draft' ? 'warning' : 'success'}`}>
                        {inv.status === 'draft' ? 'Draft' : 'Final'}
                      </span>
                    </td>
                    <td className="text-right font-mono">{formatCurrency(inv.grandTotal)}</td>
                    <td className="text-right font-mono" style={{ color: 'var(--success)' }}>{formatCurrency(inv.paidAmount)}</td>
                    <td className="text-right font-mono" style={{ color: inv.dueAmount > 0 ? 'var(--danger)' : 'var(--text-muted)', fontWeight: inv.dueAmount > 0 ? 700 : 400 }}>
                      {formatCurrency(inv.dueAmount)}
                    </td>
                    <td>
                      <span className={`badge badge-${inv.paymentStatus === 'paid' ? 'success' : inv.paymentStatus === 'partial' ? 'warning' : 'danger'}`}>
                        {inv.paymentStatus}
                      </span>
                    </td>
                    <td style={{ display: 'flex', gap: 5 }}>
                      <Link to={`/billing/${inv._id}`} className="btn btn-secondary btn-sm">View</Link>
                      <Link to={`/billing/edit/${inv._id}`} className="btn btn-secondary btn-sm">Edit</Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
        <Pagination page={page} pages={pages} onPage={setPage} />
      </div>
    </Layout>
  );
}
